import React from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';

import CheckInPage from './pages/CheckInPage';
import LoginPage from './pages/LoginPage';
import DashboardLayout from './layouts/DashboardLayout';
import Dashboard from './pages/Dashboard';
import ParticipantsPage from './pages/ParticipantsPage';
import VolunteersPage from './pages/VolunteersPage';
import ReportsPage from './pages/ReportsPage';
import CommissionsPage from './pages/CommissionsPage';
import ImportPage from './pages/ImportPage';
import RegisterVolunteerPage from './pages/RegisterVolunteerPage';

import { AuthProvider, useAuth } from './context/AuthContext';

function PrivateRoute({ children }) {
  const { user, loading } = useAuth();
  if (loading) return <div className="loading"><div className="spinner" /></div>;
  return user ? children : <Navigate to="/login" replace />;
}

export default function App() {
  return (
    <AuthProvider>
      <BrowserRouter>
        <Toaster
          position="top-right"
          toastOptions={{
            style: {
              background: '#1d3461',
              color: '#f0f4f8',
              border: '1px solid rgba(201,168,76,0.3)',
              fontFamily: 'IBM Plex Sans, sans-serif',
              fontSize: '0.875rem',
            },
            success: { iconTheme: { primary: '#c9a84c', secondary: '#0a1628' } },
          }}
        />
        <Routes>
          {/* PUBLICA */}
          <Route path="/checkin" element={<CheckInPage />} />
          <Route path="/registro-voluntario" element={<RegisterVolunteerPage />} />
          <Route path="/login" element={<LoginPage />} />

          {/* PRIVADA - PANEL ADMIN */}
          <Route path="/panel" element={
            <PrivateRoute>
              <DashboardLayout />
            </PrivateRoute>
          }>
            <Route index element={<Dashboard />} />
            <Route path="participantes" element={<ParticipantsPage />} />
            <Route path="voluntarios" element={<VolunteersPage />} />
            <Route path="informes" element={<ReportsPage />} />
            <Route path="comisiones" element={<CommissionsPage />} />
            <Route path="importar" element={<ImportPage />} />
          </Route>

          <Route path="/" element={<Navigate to="/checkin" replace />} />
          <Route path="*" element={<Navigate to="/checkin" replace />} />
        </Routes>
      </BrowserRouter>
    </AuthProvider>
  );
}
